3	namespace Illuminate\Foundation\Http;
4	
5	use Carbon\CarbonInterval;
6	use DateTimeInterface;
7	use Illuminate\Contracts\Debug\ExceptionHandler;
8	use Illuminate\Contracts\Foundation\Application;
9	use Illuminate\Contracts\Http\Kernel as KernelContract;
10	use Illuminate\Foundation\Events\Terminating;
11	use Illuminate\Foundation\Http\Events\RequestHandled;
12	use Illuminate\Routing\Pipeline;
13	use Illuminate\Routing\Router;
14	use Illuminate\Support\Carbon;
15	use Illuminate\Support\Facades\Request;
16	use Illuminate\Support\InteractsWithTime;
17	use InvalidArgumentException;
18	use Throwable;
19	
20	class Kernel implements KernelContract
21	{
22	    use InteractsWithTime;
23	
24	    /**
25	     * The application implementation.
26	     *
27	     * @var \Illuminate\Contracts\Foundation\Application
28	     */
29	    protected $app;
30	
31	    /**
32	     * The router instance.
33	     *
34	     * @var \Illuminate\Routing\Router
35	     */
36	    protected $router;
37	
38	    /**
39	     * The bootstrap classes for the application.
40	     *
41	     * @var string[]
42	     */
43	    protected $bootstrappers = [
44	        \Illuminate\Foundation\Bootstrap\LoadEnvironmentVariables::class,
45	        \Illuminate\Foundation\Bootstrap\LoadConfiguration::class,
46	        \Illuminate\Foundation\Bootstrap\HandleExceptions::class,
47	        \Illuminate\Foundation\Bootstrap\RegisterFacades::class,
48	        \Illuminate\Foundation\Bootstrap\RegisterProviders::class,
49	        \Illuminate\Foundation\Bootstrap\BootProviders::class,
50	    ];
51	
52	    /**
53	     * The application's middleware stack.
54	     *
55	     * @var array<int, class-string|string>
56	     */
57	    protected $middleware = [];
58	
59	    /**
60	     * The application's route middleware groups.
61	     *
62	     * @var array<string, array<int, class-string|string>>
63	     */
64	    protected $middlewareGroups = [];
65	
66	    /**
67	     * The application's route middleware.
68	     *
69	     * @var array<string, class-string|string>
70	     *
71	     * @deprecated
72	     */
73	    protected $routeMiddleware = [];
74	
75	    /**
76	     * The application's middleware aliases.
77	     *
78	     * @var array<string, class-string|string>
79	     */
80	    protected $middlewareAliases = [];
81	
82	    /**
83	     * All of the registered request duration handlers.
84	     *
85	     * @var array
86	     */
87	    protected $requestLifecycleDurationHandlers = [];
88	
89	    /**
90	     * When the kernel starting handling the current request.
91	     *
92	     * @var \Illuminate\Support\Carbon|null
93	     */
94	    protected $requestStartedAt;
95	
96	    /**
97	     * The priority-sorted list of middleware.
98	     *
99	     * Forces non-global middleware to always be in the given order.
100	     *
101	     * @var string[]
102	     */
103	    protected $middlewarePriority = [
104	        \Illuminate\Foundation\Http\Middleware\HandlePrecognitiveRequests::class,
105	        \Illuminate\Cookie\Middleware\EncryptCookies::class,
106	        \Illuminate\Cookie\Middleware\AddQueuedCookiesToResponse::class,
107	        \Illuminate\Session\Middleware\StartSession::class,
108	        \Illuminate\View\Middleware\ShareErrorsFromSession::class,
109	        \Illuminate\Contracts\Auth\Middleware\AuthenticatesRequests::class,
110	        \Illuminate\Routing\Middleware\ThrottleRequests::class,
111	        \Illuminate\Routing\Middleware\ThrottleRequestsWithRedis::class,
112	        \Illuminate\Contracts\Session\Middleware\AuthenticatesSessions::class,
113	        \Illuminate\Routing\Middleware\SubstituteBindings::class,
114	        \Illuminate\Auth\Middleware\Authorize::class,
115	    ];
116	
117	    /**
118	     * Create a new HTTP kernel instance.
119	     *
120	     * @param  \Illuminate\Contracts\Foundation\Application  $app
121	     * @param  \Illuminate\Routing\Router  $router
122	     */
123	    public function __construct(Application $app, Router $router)
124	    {
125	        $this->app = $app;
126	        $this->router = $router;
127	
128	        $this->syncMiddlewareToRouter();
129	    }
130	
131	    /**
132	     * Handle an incoming HTTP request.
133	     *
134	     * @param  \Illuminate\Http\Request  $request
135	     * @return \Illuminate\Http\Response
136	     */
137	    public function handle($request)
138	    {
139	        $this->requestStartedAt = Carbon::now();
140	
141	        try {
142	            $request->enableHttpMethodParameterOverride();
143	
144	            $response = $this->sendRequestThroughRouter($request);
145	        } catch (Throwable $e) {
146	            $this->reportException($e);
147	
148	            $response = $this->renderException($request, $e);
149	        }
150	
151	        $this->app['events']->dispatch(
152	            new RequestHandled($request, $response)
153	        );
154	
155	        return $response;
156	    }
157	
158	    /**
159	     * Send the given request through the middleware / router.
160	     *
161	     * @param  \Illuminate\Http\Request  $request
162	     * @return \Illuminate\Http\Response
163	     */
164	    protected function sendRequestThroughRouter($request)
165	    {
166	        $this->app->instance('request', $request);
167	
168	        Request::clearResolvedInstance();
169	
170	        $this->bootstrap();
171	
172	        return (new Pipeline($this->app))
173	            ->send($request)
174	            ->through($this->app->shouldSkipMiddleware() ? [] : $this->middleware)
175	            ->then($this->dispatchToRouter());
176	    }
177	
178	    /**
179	     * Bootstrap the application for HTTP requests.
180	     *
181	     * @return void
182	     */
183	    public function bootstrap()
184	    {
185	        if (! $this->app->hasBeenBootstrapped()) {
186	            $this->app->bootstrapWith($this->bootstrappers());
187	        }
188	    }
189	
190	    /**
191	     * Get the route dispatcher callback.
192	     *
193	     * @return \Closure
194	     */
195	    protected function dispatchToRouter()
196	    {
197	        return function ($request) {
198	            $this->app->instance('request', $request);
199	
200	            return $this->router->dispatch($request);
201	        };
202	    }
203	
204	    /**
205	     * Call the terminate method on any terminable middleware.
206	     *
207	     * @param  \Illuminate\Http\Request  $request
208	     * @param  \Illuminate\Http\Response  $response
209	     * @return void
210	     */
211	    public function terminate($request, $response)
212	    {
213	        $this->app['events']->dispatch(new Terminating);
214	
215	        $this->terminateMiddleware($request, $response);
216	
217	        $this->app->terminate();
218	
219	        if ($this->requestStartedAt === null) {
220	            return;
221	        }
222	
223	        $this->requestStartedAt->setTimezone($this->app['config']->get('app.timezone') ?? 'UTC');
224	
225	        foreach ($this->requestLifecycleDurationHandlers as ['threshold' => $threshold, 'handler' => $handler]) {
226	            $end ??= Carbon::now();
227	
228	            if ($this->requestStartedAt->diffInMilliseconds($end) > $threshold) {
229	                $handler($this->requestStartedAt, $request, $response);
230	            }
231	        }
232	
233	        $this->requestStartedAt = null;
234	    }
235	
236	    /**
237	     * Call the terminate method on any terminable middleware.
238	     *
239	     * @param  \Illuminate\Http\Request  $request
240	     * @param  \Illuminate\Http\Response  $response
241	     * @return void
242	     */
243	    protected function terminateMiddleware($request, $response)
244	    {
245	        $middlewares = $this->app->shouldSkipMiddleware() ? [] : array_merge(
246	            $this->gatherRouteMiddleware($request),
247	            $this->middleware
248	        );
249	
250	        foreach ($middlewares as $middleware) {
251	            if (! is_string($middleware)) {
252	                continue;
253	            }
254	
255	            [$name] = $this->parseMiddleware($middleware);
256	
257	            $instance = $this->app->make($name);
258	
259	            if (method_exists($instance, 'terminate')) {
260	                $instance->terminate($request, $response);
261	            }
262	        }
263	    }
264	
265	    /**
266	     * Register a callback to be invoked when the requests lifecycle duration exceeds a given amount of time.
267	     *
268	     * @param  \DateTimeInterface|\Carbon\CarbonInterval|float|int  $threshold
269	     * @param  callable  $handler
270	     * @return void
271	     */
272	    public function whenRequestLifecycleIsLongerThan($threshold, $handler)
273	    {
274	        $threshold = $threshold instanceof DateTimeInterface
275	            ? $this->secondsUntil($threshold) * 1000
276	            : $threshold;
277	
278	        $threshold = $threshold instanceof CarbonInterval
279	            ? $threshold->totalMilliseconds
280	            : $threshold;
281	
282	        $this->requestLifecycleDurationHandlers[] = [
283	            'threshold' => $threshold,
284	            'handler' => $handler,
285	        ];
286	    }
287	
288	    /**
289	     * When the request being handled started.
290	     *
291	     * @return \Illuminate\Support\Carbon|null
292	     */
293	    public function requestStartedAt()
294	    {
295	        return $this->requestStartedAt;
296	    }
297	
298	    /**
299	     * Gather the route middleware for the given request.
300	     *
301	     * @param  \Illuminate\Http\Request  $request
302	     * @return array
303	     */
304	    protected function gatherRouteMiddleware($request)
305	    {
306	        if ($route = $request->route()) {
307	            return $this->router->gatherRouteMiddleware($route);
308	        }
309	
310	        return [];
311	    }
312	
313	    /**
314	     * Parse a middleware string to get the name and parameters.
315	     *
316	     * @param  string  $middleware
317	     * @return array
318	     */
319	    protected function parseMiddleware($middleware)
320	    {
321	        [$name, $parameters] = array_pad(explode(':', $middleware, 2), 2, []);
322	
323	        if (is_string($parameters)) {
324	            $parameters = explode(',', $parameters);
325	        }
326	
327	        return [$name, $parameters];
328	    }
329	
330	    /**
331	     * Determine if the kernel has a given middleware.
332	     *
333	     * @param  string  $middleware
334	     * @return bool
335	     */
336	    public function hasMiddleware($middleware)
337	    {
338	        return in_array($middleware, $this->middleware);
339	    }
340	
341	    /**
342	     * Add a new middleware to the beginning of the stack if it does not already exist.
343	     *
344	     * @param  string  $middleware
345	     * @return $this
346	     */
347	    public function prependMiddleware($middleware)
348	    {
349	        if (array_search($middleware, $this->middleware) === false) {
350	            array_unshift($this->middleware, $middleware);
351	        }
352	
353	        return $this;
354	    }
355	
356	    /**
357	     * Add a new middleware to end of the stack if it does not already exist.
358	     *
359	     * @param  string  $middleware
360	     * @return $this
361	     */
362	    public function pushMiddleware($middleware)
363	    {
364	        if (array_search($middleware, $this->middleware) === false) {
365	            $this->middleware[] = $middleware;
366	        }
367	
368	        return $this;
369	    }
370	
371	    /**
372	     * Prepend the given middleware to the given middleware group.
373	     *
374	     * @param  string  $group
375	     * @param  string  $middleware
376	     * @return $this
377	     *
378	     * @throws \InvalidArgumentException
379	     */
380	    public function prependMiddlewareToGroup($group, $middleware)
381	    {
382	        if (! isset($this->middlewareGroups[$group])) {
383	            throw new InvalidArgumentException("The [{$group}] middleware group has not been defined.");
384	        }
385	
386	        if (array_search($middleware, $this->middlewareGroups[$group]) === false) {
387	            array_unshift($this->middlewareGroups[$group], $middleware);
388	        }
389	
390	        $this->syncMiddlewareToRouter();
391	
392	        return $this;
393	    }
394	
395	    /**
396	     * Append the given middleware to the given middleware group.
397	     *
398	     * @param  string  $group
399	     * @param  string  $middleware
400	     * @return $this
401	     *
402	     * @throws \InvalidArgumentException
403	     */
404	    public function appendMiddlewareToGroup($group, $middleware)
405	    {
406	        if (! isset($this->middlewareGroups[$group])) {
407	            throw new InvalidArgumentException("The [{$group}] middleware group has not been defined.");
408	        }
409	
410	        if (array_search($middleware, $this->middlewareGroups[$group]) === false) {
411	            $this->middlewareGroups[$group][] = $middleware;
412	        }
413	
414	        $this->syncMiddlewareToRouter();
415	
416	        return $this;
417	    }
418	
419	    /**
420	     * Prepend the given middleware to the middleware priority list.
421	     *
422	     * @param  string  $middleware
423	     * @return $this
424	     */
425	    public function prependToMiddlewarePriority($middleware)
426	    {
427	        if (! in_array($middleware, $this->middlewarePriority)) {
428	            array_unshift($this->middlewarePriority, $middleware);
429	        }
430	
431	        $this->syncMiddlewareToRouter();
432	
433	        return $this;
434	    }
435	
436	    /**
437	     * Append the given middleware to the middleware priority list.
438	     *
439	     * @param  string  $middleware
440	     * @return $this
441	     */
442	    public function appendToMiddlewarePriority($middleware)
443	    {
444	        if (! in_array($middleware, $this->middlewarePriority)) {
445	            $this->middlewarePriority[] = $middleware;
446	        }
447	
448	        $this->syncMiddlewareToRouter();
449	
450	        return $this;
451	    }
452	
453	    /**
454	     * Add the given middleware to the middleware priority list before other middleware.
455	     *
456	     * @param  array|string  $before
457	     * @param  string  $middleware
458	     * @return $this
459	     */
460	    public function addToMiddlewarePriorityBefore($before, $middleware)
461	    {
462	        return $this->addToMiddlewarePriorityRelative($before, $middleware, after: false);
463	    }
464	
465	    /**
466	     * Add the given middleware to the middleware priority list after other middleware.
467	     *
468	     * @param  array|string  $after
469	     * @param  string  $middleware
470	     * @return $this
471	     */
472	    public function addToMiddlewarePriorityAfter($after, $middleware)
473	    {
474	        return $this->addToMiddlewarePriorityRelative($after, $middleware);
475	    }
476	
477	    /**
478	     * Add the given middleware to the middleware priority list relative to other middleware.
479	     *
480	     * @param  string|array  $existing
481	     * @param  string  $middleware
482	     * @param  bool  $after
483	     * @return $this
484	     */
485	    protected function addToMiddlewarePriorityRelative($existing, $middleware, $after = true)
486	    {
487	        if (! in_array($middleware, $this->middlewarePriority)) {
488	            $index = $after ? 0 : count($this->middlewarePriority);
489	
490	            foreach ((array) $existing as $existingMiddleware) {
491	                if (in_array($existingMiddleware, $this->middlewarePriority)) {
492	                    $middlewareIndex = array_search($existingMiddleware, $this->middlewarePriority);
493	
494	                    if ($after && $middlewareIndex > $index) {
495	                        $index = $middlewareIndex + 1;
496	                    } elseif ($after === false && $middlewareIndex < $index) {
497	                        $index = $middlewareIndex;
498	                    }
499	                }
500	            }
501	
502	            if ($index === 0 && $after === false) {
503	                array_unshift($this->middlewarePriority, $middleware);
504	            } elseif (($after && $index === 0) || $index === count($this->middlewarePriority)) {
505	                $this->middlewarePriority[] = $middleware;
506	            } else {
507	                array_splice($this->middlewarePriority, $index, 0, $middleware);
508	            }
509	        }
510	
511	        $this->syncMiddlewareToRouter();
512	
513	        return $this;
514	    }
515	
516	    /**
517	     * Sync the current state of the middleware to the router.
518	     *
519	     * @return void
520	     */
521	    protected function syncMiddlewareToRouter()
522	    {
523	        $this->router->middlewarePriority = $this->middlewarePriority;
524	
525	        foreach ($this->middlewareGroups as $key => $middleware) {
526	            $this->router->middlewareGroup($key, $middleware);
527	        }
528	
529	        foreach (array_merge($this->routeMiddleware, $this->middlewareAliases) as $key => $middleware) {
530	            $this->router->aliasMiddleware($key, $middleware);
531	        }
532	    }
