613	     * Set the application's middleware groups.
614	     *
615	     * @param  array  $groups
616	     * @return $this
617	     */
618	    public function setMiddlewareGroups(array $groups)
619	    {
620	        $this->middlewareGroups = $groups;
621	
622	        $this->syncMiddlewareToRouter();
623	
624	        return $this;
625	    }
626	
627	    /**
628	     * Get the application's route middleware aliases.
629	     *
630	     * @return array
631	     *
632	     * @deprecated
633	     */
634	    public function getRouteMiddleware()
635	    {
636	        return $this->getMiddlewareAliases();
