1193	        $attributes = new Collection;
1194	
1195	        $current = $reflectionClass;
1196	
1197	        while ($current) {
1198	            $classAttributes = array_reverse($current->getAttributes(
1199	                MiddlewareAttribute::class, ReflectionAttribute::IS_INSTANCEOF
1200	            ));
