1208	
1209	        return $attributes->merge(
1210	            $reflectionMethod->getAttributes(MiddlewareAttribute::class, ReflectionAttribute::IS_INSTANCEOF)
1211	        )->map(function (ReflectionAttribute $attribute) use ($method) {
1212	            $instance = $attribute->newInstance();
